UPDATE E_MAT_WAREHOUSE_OUT_APP_DETAIL
SET DEL_FLAG = 1,
    DELETE_BY = #{loginUserId,jdbcType=BIGINT},
    DELETE_BY_NAME = #{loginUserName,jdbcType=VARCHAR},
    DELETE_TIME = #{now,jdbcType=TIMESTAMP}
WHERE WAREHOUSE_OUT_APP_ID = #{id}

UPDATE E_MAT_WAREHOUSE_OUT_APP_DETAIL
SET DEL_FLAG = 1,
    DELETE_BY = #{loginUserId,jdbcType=BIGINT},
    DELETE_BY_NAME = #{loginUserName,jdbcType=VARCHAR},
    DELETE_TIME = #{now,jdbcType=TIMESTAMP}
WHERE ID = #{id}

UPDATE E_MAT_WAREHOUSE_OUT_APP_DETAIL
SET OUT_QUANTITY_SUM = NVL(OUT_QUANTITY_SUM, 0) + #{outQuantity,jdbcType=NUMERIC}
WHERE ID = #{id}

UPDATE E_MAT_WAREHOUSE_OUT_APP_DETAIL
SET OUT_QUANTITY_SUM = GREATEST(NVL(OUT_QUANTITY_SUM, 0) - #{outQuantity,jdbcType=NUMERIC}, 0)
WHERE ID = #{id}
